import React, { useState, useMemo } from 'react';

function getPrimes(limit: number): number[] {
  const sieve = Array(limit + 1).fill(true);
  sieve[0] = sieve[1] = false;
  for (let i = 2; i * i <= limit; i++) {
    if (sieve[i]) for (let j = i * i; j <= limit; j += i) sieve[j] = false;
  }
  return sieve.reduce<number[]>((acc, v, i) => (v ? [...acc, i] : acc), []);
}

function PrimeList() {
  const [limit, setLimit] = useState(100);
  const [query, setQuery] = useState('');
  const primes = useMemo(() => getPrimes(limit), [limit]);

  return (
    <div>
      <input type="number" value={limit} onChange={(e) => setLimit(+e.target.value)} />
      <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="검색" />
      <p>소수 {primes.length}개</p>
      <ul>{primes.filter((p) => String(p).includes(query)).map((p) => <li key={p}>{p}</li>)}</ul>
    </div>
  );
}

export default PrimeList;

import React, { Component, ErrorInfo } from 'react';

interface Props { fallback?: React.ReactNode; children: React.ReactNode; }
interface State { hasError: boolean; error: Error | null; }

class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: ErrorInfo) {
    console.error('ErrorBoundary caught:', error, info.componentStack);
  }

  render() {
    if (this.state.hasError) {
      return this.props.fallback ?? <div>오류: {this.state.error?.message}</div>;
    }
    return this.props.children;
  }
}

export default ErrorBoundary;

