import { useState, useCallback } from 'react';

interface Options { min?: number; max?: number; step?: number; }

function useCounter(init = 0, { min = -Infinity, max = Infinity, step = 1 }: Options = {}) {
  const [count, setCount] = useState(() => Math.min(Math.max(init, min), max));
  const increment = useCallback(() => setCount((c) => Math.min(c + step, max)), [step, max]);
  const decrement = useCallback(() => setCount((c) => Math.max(c - step, min)), [step, min]);
  const reset = useCallback(() => setCount(init), [init]);
  return { count, increment, decrement, reset, isMin: count <= min, isMax: count >= max };
}

