import { useState, useCallback } from 'react';

function useStep(totalSteps: number) {
  const [step, setStep] = useState(0);
  const next = useCallback(() => setStep((s) => Math.min(s + 1, totalSteps - 1)), [totalSteps]);
  const prev = useCallback(() => setStep((s) => Math.max(s - 1, 0)), []);
  const goTo = useCallback((s: number) => setStep(Math.min(Math.max(s, 0), totalSteps - 1)), [totalSteps]);
  const reset = useCallback(() => setStep(0), []);
  return { step, next, prev, goTo, reset, isFirst: step === 0, isLast: step === totalSteps - 1 };
}

const STEPS = ['기본 정보', '주소', '확인'];
function Wizard() {
  const { step, next, prev, isFirst, isLast } = useStep(STEPS.length);
  return (
    <div>
      <p>단계 {step + 1}/{STEPS.length}: {STEPS[step]}</p>
      <button onClick={prev} disabled={isFirst}>이전</button>
      <button onClick={next} disabled={isLast}>다음</button>
    </div>
  );
}

export { useStep };

