import { useState, useMemo } from 'react';

function usePagination<T>(items: T[], size: number) {
  const [page, setPage] = useState(1);
  const total = Math.max(1, Math.ceil(items.length / size));
  const current = useMemo(() => items.slice((page - 1) * size, page * size), [items, page, size]);
  const goTo = (p: number) => setPage(Math.min(Math.max(p, 1), total));
  return { current, page, total, goTo, hasPrev: page > 1, hasNext: page < total };
}

function NumberList() {
  const nums = Array.from({ length: 50 }, (_, i) => i + 1);
  const { current, page, total, goTo, hasPrev, hasNext } = usePagination(nums, 5);
  return (
    <div>
      <ul>{current.map((n) => <li key={n}>{n}</li>)}</ul>
      <button onClick={() => goTo(page - 1)} disabled={!hasPrev}>이전</button>
      <span> {page}/{total} </span>
      <button onClick={() => goTo(page + 1)} disabled={!hasNext}>다음</button>
    </div>
  );
}

export { usePagination };

import { useState, useCallback } from 'react';

type AsyncStatus = 'idle' | 'pending' | 'success' | 'error';

function useAsync<T, Args extends unknown[]>(asyncFn: (...args: Args) => Promise<T>) {
  const [status, setStatus] = useState<AsyncStatus>('idle');
  const [data, setData] = useState<T | null>(null);
  const [error, setError] = useState<Error | null>(null);

  const run = useCallback(async (...args: Args) => {
    setStatus('pending');
    setError(null);
    try {
      const result = await asyncFn(...args);
      setData(result);
      setStatus('success');
      return result;
    } catch (e) {
      setError(e instanceof Error ? e : new Error(String(e)));
      setStatus('error');
    }
  }, [asyncFn]);

  return { run, status, data, error, isLoading: status === 'pending' };
}

