import { useState, useCallback, useRef } from 'react';

function useFieldArray<T>(initialValue: T) {
  const idRef = useRef(0);
  const [fields, setFields] = useState<(T & { _id: number })[]>([]);

  const append = useCallback((value?: Partial<T>) =>
    setFields((f) => [...f, { ...initialValue, ...value, _id: ++idRef.current } as T & { _id: number }]),
    [initialValue]);

  const remove = useCallback((id: number) =>
    setFields((f) => f.filter((item) => item._id !== id)), []);

  return { fields, append, remove };
}

function TagInput() {
  const { fields, append, remove } = useFieldArray({ name: '' });
  return (
    <div>
      {fields.map((f) => (
        <span key={f._id}>{f.name} <button onClick={() => remove(f._id)}>x</button></span>
      ))}
      <button onClick={() => append({ name: `태그${fields.length + 1}` })}>추가</button>
    </div>
  );
}

export { useFieldArray };

import React, { useState, useRef, useEffect } from 'react';

type Item = { label: string; onClick: () => void };

function Dropdown({ trigger, items }: { trigger: React.ReactNode; items: Item[] }) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const h = (e: MouseEvent) => { if (!ref.current?.contains(e.target as Node)) setOpen(false); };
    document.addEventListener('mousedown', h);
    return () => document.removeEventListener('mousedown', h);
  }, []);
  return (
    <div ref={ref} className="dropdown">
      <button onClick={() => setOpen((o) => !o)} aria-haspopup="true" aria-expanded={open}>{trigger}</button>
      {open && (
        <ul role="menu" className="dropdown-menu">
          {items.map((it, i) => (
            <li key={i} role="menuitem" className="dropdown-item" onClick={() => { it.onClick(); setOpen(false); }}>{it.label}</li>
          ))}
        </ul>
      )}
    </div>
  );
}
export default Dropdown;

