import React, { useRef, useState, useEffect } from 'react';

function LazyImage({ src, alt, ...props }: React.ImgHTMLAttributes<HTMLImageElement> & { src: string }) {
  const [loaded, setLoaded] = useState(false);
  const [imgSrc, setImgSrc] = useState('');
  const ref = useRef<HTMLImageElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        setImgSrc(src);
        observer.disconnect();
      }
    }, { threshold: 0.1 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [src]);

  return (
    <img
      ref={ref}
      src={imgSrc}
      alt={alt}
      onLoad={() => setLoaded(true)}
      style={{ opacity: loaded ? 1 : 0, transition: 'opacity 0.3s', ...props.style }}
      {...props}
    />
  );
}

export default LazyImage;

import { useState, useMemo } from 'react';

function useSearch<T extends Record<string, unknown>>(items: T[], keys: (keyof T)[]) {
  const [query, setQuery] = useState('');

  const filtered = useMemo(() => {
    if (!query.trim()) return items;
    const lower = query.toLowerCase();
    return items.filter((item) =>
      keys.some((key) => String(item[key] ?? '').toLowerCase().includes(lower))
    );
  }, [items, keys, query]);

  return { query, setQuery, filtered };
}

