type Opt = { value: string; label: string };

function AsyncSelect({ load, onChange }: { load: (q: string) => Promise<Opt[]>; onChange: (o: Opt) => void }) {
  const [q, setQ] = useState('');
  const [opts, setOpts] = useState<Opt[]>([]);
  const [open, setOpen] = useState(false);

  useEffect(() => {
    if (!q) { setOpts([]); return; }
    const t = setTimeout(() => load(q).then((o) => { setOpts(o); setOpen(!!o.length); }), 300);
    return () => clearTimeout(t);
  }, [q, load]);

  return (
    <div style={{ position: 'relative' }}>
      <input value={q} onChange={(e) => setQ(e.target.value)} placeholder="검색..." />
      {open && (
        <ul style={{ position: 'absolute', background: '#fff', border: '1px solid #ddd', width: '100%' }}>
          {opts.map((o) => (
            <li key={o.value} onClick={() => { onChange(o); setQ(o.label); setOpen(false); }} style={{ padding: 6 }}>{o.label}</li>
          ))}
        </ul>
      )}
    </div>
  );
}
export default AsyncSelect;

import { useState, useCallback } from 'react';

function useSelection<T>(items: T[], getId: (item: T) => string) {
  const [selected, setSelected] = useState<Set<string>>(new Set());

  const toggle = useCallback((item: T) => {
    const id = getId(item);
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }, [getId]);

  const selectAll = useCallback(() => setSelected(new Set(items.map(getId))), [items, getId]);
  const clearAll = useCallback(() => setSelected(new Set()), []);
  const isSelected = useCallback((item: T) => selected.has(getId(item)), [selected, getId]);

  return { selected, toggle, selectAll, clearAll, isSelected, count: selected.size };
}

export { useSelection };

