async function apiToggleLike(id: number, liked: boolean): Promise<void> {
  const res = await fetch(`/api/posts/${id}/like`, { method: liked ? 'POST' : 'DELETE' });
  if (!res.ok) throw new Error('요청 실패');
}

function LikeButton({ postId, initialLiked, initialCount }: { postId: number; initialLiked: boolean; initialCount: number }) {
  const [liked, setLiked] = useState(initialLiked);
  const [count, setCount] = useState(initialCount);

  const handleClick = async () => {
    const nextLiked = !liked;
    setLiked(nextLiked);
    setCount((c) => c + (nextLiked ? 1 : -1));
    try {
      await apiToggleLike(postId, nextLiked);
    } catch {
      setLiked(liked);
      setCount(count);
    }
  };

  return (
    <button onClick={handleClick} style={{ color: liked ? '#e53e3e' : '#718096' }}>
      {liked ? '♥' : '♡'} {count}
    </button>
  );
}

