import React, { useState, useMemo } from 'react';

function VirtualList<T>({ items, ih, ch, render }: {
  items: T[]; ih: number; ch: number;
  render: (item: T, i: number) => React.ReactNode;
}) {
  const [top, setTop] = useState(0);
  const os = 3;
  const { s, e } = useMemo(() => {
    const s = Math.max(0, Math.floor(top / ih) - os);
    return { s, e: Math.min(items.length - 1, s + Math.ceil(ch / ih) + os * 2) };
  }, [top, ih, ch, items.length]);

  return (
    <div style={{ height: ch, overflowY: 'auto' }} onScroll={(ev) => setTop(ev.currentTarget.scrollTop)}>
      <div style={{ height: items.length * ih, position: 'relative' }}>
        {items.slice(s, e + 1).map((item, i) => (
          <div key={s + i} style={{ position: 'absolute', top: (s + i) * ih, width: '100%', height: ih }}>
            {render(item, s + i)}
          </div>
        ))}
      </div>
    </div>
  );
}

export default VirtualList;

