import React, { useState, useEffect } from 'react';

interface TypewriterProps {
  text: string;
  speed?: number;
  onDone?: () => void;
}

function Typewriter({ text, speed = 50, onDone }: TypewriterProps) {
  const [displayed, setDisplayed] = useState('');

  useEffect(() => {
    setDisplayed('');
    if (!text) return;
    let i = 0;
    const id = setInterval(() => {
      i += 1;
      setDisplayed(text.slice(0, i));
      if (i >= text.length) {
        clearInterval(id);
        onDone?.();
      }
    }, speed);
    return () => clearInterval(id);
  }, [text, speed, onDone]);

  return (
    <span>
      {displayed}
      {displayed.length < text.length && <span style={{ borderRight: '2px solid currentColor', animation: 'blink 1s step-end infinite' }} />}
    </span>
  );
}

export default Typewriter;

