import React, { useState } from 'react';

function ResizablePanel({ dw = 300, min = 100, max = 800, children }: {
  dw?: number; min?: number; max?: number; children: React.ReactNode;
}) {
  const [w, setW] = useState(dw);

  const onDown = (e: React.MouseEvent) => {
    e.preventDefault();
    const x0 = e.clientX, w0 = w;
    const mv = (ev: MouseEvent) => setW(Math.min(Math.max(w0 + ev.clientX - x0, min), max));
    const up = () => { window.removeEventListener('mousemove', mv); window.removeEventListener('mouseup', up); };
    window.addEventListener('mousemove', mv);
    window.addEventListener('mouseup', up);
  };

  return (
    <div style={{ display: 'flex', width: w }}>
      <div style={{ flex: 1, overflow: 'auto' }}>{children}</div>
      <div onMouseDown={onDown} style={{ width: 4, cursor: 'ew-resize', background: '#e5e7eb' }} />
    </div>
  );
}

export default ResizablePanel;

import { useState, useEffect, useCallback } from 'react';

function useQueryParam(key: string, defaultValue: string): [string, (v: string) => void] {
  const getFromUrl = () => {
    const params = new URLSearchParams(window.location.search);
    return params.get(key) ?? defaultValue;
  };

  const [value, setValue] = useState(getFromUrl);

  const setParam = useCallback((newVal: string) => {
    const params = new URLSearchParams(window.location.search);
    if (newVal === defaultValue) params.delete(key);
    else params.set(key, newVal);
    const newUrl = `${window.location.pathname}${params.toString() ? '?' + params.toString() : ''}`;
    window.history.replaceState(null, '', newUrl);
    setValue(newVal);
  }, [key, defaultValue]);

  useEffect(() => { setValue(getFromUrl()); }, []);

  return [value, setParam];
}

export { useQueryParam };

import React, { useEffect, useRef, useState } from 'react';

function CountUp({ to, duration = 1000, prefix = '', suffix = '' }: { to: number; duration?: number; prefix?: string; suffix?: string }) {
  const [current, setCurrent] = useState(0);
  const startRef = useRef<number | null>(null);
  const fromRef = useRef(0);

  useEffect(() => {
    fromRef.current = current;
    startRef.current = null;
    const step = (ts: number) => {
      if (!startRef.current) startRef.current = ts;
      const p = Math.min((ts - startRef.current) / duration, 1);
      const eased = 1 - Math.pow(1 - p, 3);
      setCurrent(Math.round(fromRef.current + (to - fromRef.current) * eased));
      if (p < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [to, duration]);

  return <span>{prefix}{current.toLocaleString()}{suffix}</span>;
}

export default CountUp;

import React, { useMemo } from 'react';

function parseMarkdown(md: string): string {
  return md
    .replace(/^### (.+)$/gm, '<h3>$1</h3>')
    .replace(/^## (.+)$/gm, '<h2>$1</h2>')
    .replace(/^# (.+)$/gm, '<h1>$1</h1>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/`(.+?)`/g, '<code>$1</code>')
    .replace(/^[-*] (.+)$/gm, '<li>$1</li>')
    .replace(/\n{2,}/g, '</p><p>')
    .replace(/^(?!<[h|u|l])(.+)$/gm, '<p>$1</p>');
}

function MarkdownRenderer({ content }: { content: string }) {
  const html = useMemo(() => parseMarkdown(content), [content]);
  return <div dangerouslySetInnerHTML={{ __html: html }} style={{ lineHeight: 1.7 }} />;
}

export default MarkdownRenderer;

import { useState, useEffect } from 'react';

interface GeoState {
  loading: boolean;
  error: string | null;
  coords: { lat: number; lng: number } | null;
}

function useGeolocation(): GeoState {
  const [state, setState] = useState<GeoState>({ loading: true, error: null, coords: null });

  useEffect(() => {
    if (!navigator.geolocation) {
      setState({ loading: false, error: 'Geolocation 미지원', coords: null });
      return;
    }
    navigator.geolocation.getCurrentPosition(
      (pos) => setState({ loading: false, error: null, coords: { lat: pos.coords.latitude, lng: pos.coords.longitude } }),
      (err) => setState({ loading: false, error: err.message, coords: null })
    );
  }, []);

  return state;
}

function LocationDisplay() {
  const { loading, error, coords } = useGeolocation();
  if (loading) return <p>위치 확인 중...</p>;
  if (error) return <p>오류: {error}</p>;
  return <p>위도: {coords?.lat.toFixed(4)}, 경도: {coords?.lng.toFixed(4)}</p>;
}

export { useGeolocation };

