import React, { useState, useEffect } from 'react';

const calc = (t: Date) => {
  const d = Math.max(t.getTime() - Date.now(), 0);
  return [Math.floor(d/86400000), Math.floor(d%86400000/3600000), Math.floor(d%3600000/60000), Math.floor(d%60000/1000), !d] as const;
};

function CountdownTimer({ target }: { target: Date }) {
  const [v, setV] = useState(() => calc(target));

  useEffect(() => {
    if (v[4]) return;
    const id = setInterval(() => setV(calc(target)), 1000);
    return () => clearInterval(id);
  }, [target, v[4]]);

  if (v[4]) return <p>종료!</p>;
  const pad = (n: number) => String(n).padStart(2, '0');
  return (
    <div style={{ display: 'flex', gap: 12, fontSize: 28, fontWeight: 700 }}>
      {(['일', '시', '분', '초'] as const).map((l, k) => (
        <div key={l} style={{ textAlign: 'center' }}>
          <div>{pad(v[k])}</div>
          <div style={{ fontSize: 11, fontWeight: 400 }}>{l}</div>
        </div>
      ))}
    </div>
  );
}
export default CountdownTimer;
